import{_ as t,o as e,c as i,ag as n}from"./chunks/framework.DTiDeF2Q.js";const h=JSON.parse('{"title":"Alias Tmux | Dotfiles (ID)","titleTemplate":":title","description":"Alias Tmux adalah koleksi alias yang memungkinkan Anda berinteraksi dengan perintah `tmux`. Tmux adalah alat yang memungkinkan Anda menjalankan beberapa sesi terminal dalam satu jendela.","frontmatter":{"title":"Alias Tmux | Dotfiles","description":"Alias Tmux adalah koleksi alias yang memungkinkan Anda berinteraksi dengan perintah `tmux`. Tmux adalah alat yang memungkinkan Anda menjalankan beberapa sesi terminal dalam satu jendela.","lang":"id-ID","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Alias Tmux preview","canonical":"/id/aliases/tmux/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Alias Tmux","pageType":"docs","schemaType":"WebPage","metaTitle":"Alias Tmux - Dotfiles (ID)","permalink":"/id/aliases/tmux/","meta":[{"name":"keywords","content":"alias, tmux, linux, macos, shell, terminal, windows"},{"name":"twitter:card","content":"summary"},{"name":"twitter:description","content":"Alias Tmux adalah koleksi alias untuk berinteraksi dengan perintah `tmux`."},{"name":"twitter:title","content":"Alias Tmux - Dotfiles (ID)"},{"name":"og:title","content":"Alias Tmux - Dotfiles (ID)"},{"name":"og:description","content":"Alias Tmux adalah koleksi alias untuk berinteraksi dengan perintah `tmux`."},{"name":"og:image:alt","content":"Dotfiles - Dirancang sederhana untuk menyesuaikan kehidupan shell Anda"},{"name":"og:locale","content":"id_ID"}]},"headers":[],"relativePath":"id/aliases/tmux/index.md","filePath":"id/aliases/tmux/index.md","lastUpdated":1773010926000}'),s={name:"id/aliases/tmux/index.md"};function d(l,a,r,o,u,m){return e(),i("div",null,[...a[0]||(a[0]=[n('<h1 id="alias-tmux" tabindex="-1">Alias Tmux <a class="header-anchor" href="#alias-tmux" aria-label="Permalink to &quot;Alias Tmux&quot;">​</a></h1><p>Kelola alias Tmux. Bagian dari konfigurasi <strong>Universal Dotfiles</strong>.</p><h2 id="ikhtisar" tabindex="-1">Ikhtisar <a class="header-anchor" href="#ikhtisar" aria-label="Permalink to &quot;Ikhtisar&quot;">​</a></h2><p>Alias ini didefinisikan di <code>tmux.aliases.sh</code> dan dimuat secara otomatis oleh <code>chezmoi</code>.</p><h2 id="konfigurasi-tmux" tabindex="-1">Konfigurasi Tmux <a class="header-anchor" href="#konfigurasi-tmux" aria-label="Permalink to &quot;Konfigurasi Tmux&quot;">​</a></h2><p>Konfigurasi tmux komprehensif yang dirancang untuk produktivitas dan kemudahan penggunaan. Konfigurasi terdiri dari file modular untuk meningkatkan maintainability.</p><h3 id="fitur-utama" tabindex="-1">Fitur Utama <a class="header-anchor" href="#fitur-utama" aria-label="Permalink to &quot;Fitur Utama&quot;">​</a></h3><ul><li>Skema warna modern dengan styling status bar khusus OS</li><li>Key binding intuitif dengan Ctrl+a sebagai prefix key</li><li>Kontrol manajemen window dan pane komprehensif</li><li>Persistensi sesi dengan tmux-resurrect dan tmux-continuum</li><li>Menu bantuan yang dapat di-scroll (akses dengan <code>Ctrl+a ?</code>)</li><li>Dukungan mouse untuk navigasi mudah</li></ul><h3 id="alias" tabindex="-1">Alias <a class="header-anchor" href="#alias" aria-label="Permalink to &quot;Alias&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Deskripsi</th></tr></thead><tbody><tr><td><code>tm</code></td><td>Mulai tmux</td></tr><tr><td><code>tma</code></td><td>Attach ke sesi terakhir</td></tr><tr><td><code>tmat</code></td><td>Attach ke sesi tertentu</td></tr><tr><td><code>tmks</code></td><td>Kill semua sesi kecuali saat ini</td></tr><tr><td><code>tmka</code></td><td>Kill semua sesi (server)</td></tr><tr><td><code>tml</code></td><td>List semua sesi</td></tr><tr><td><code>tmn</code></td><td>Sesi baru tanpa nama</td></tr><tr><td><code>tms</code></td><td>Sesi baru dengan nama</td></tr><tr><td><code>tmr</code></td><td>Reload konfigurasi tmux</td></tr><tr><td><code>tmls</code></td><td>List window</td></tr><tr><td><code>tmlp</code></td><td>List pane</td></tr><tr><td><code>tmi</code></td><td>Tampilkan info tmux</td></tr></tbody></table><h2 id="penggunaan" tabindex="-1">Penggunaan <a class="header-anchor" href="#penggunaan" aria-label="Permalink to &quot;Penggunaan&quot;">​</a></h2><p>Untuk memulai sesi tmux baru:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tmux</span></span></code></pre></div><p>Atau gunakan alias yang disediakan untuk operasi umum.</p>',14)])])}const k=t(s,[["render",d]]);export{h as __pageData,k as default};
